import path from 'node:path'
import fs from 'node:fs/promises'

import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { parseEnvValue } from '@prisma/internals'

import { generateRestClient } from './generate'

export class RestClientGenerator implements Generator {
  readonly name = 'prisma-rest-client'

  async getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    const defaultOutput = config.output ? parseEnvValue(config.output) : './generated/rest-client'
    return {
      defaultOutput,
      prettyName: 'Prisma REST Client',
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = parseEnvValue(options.generator.output!)
    const code = generateRestClient(options.dmmf)
    await fs.mkdir(outputDir, { recursive: true })
    await fs.writeFile(path.join(outputDir, 'rest-client.ts'), code, 'utf-8')
  }
}
```

Key design decisions:
- `name` is `'prisma-rest-client'` -- used for registry lookup.
- `getManifest` returns a simple manifest with `defaultOutput` and `prettyName`. No engine requirements.
- `generate` writes a single file `rest-client.ts` into the output directory.
- Uses `parseEnvValue` from `@prisma/internals` (defined at `packages/internals/src/utils/parseEnvValue.ts`) exactly as existing generators do.

### 2.7 `packages/generator-rest-client/src/generate.ts`

The core generation logic. Takes a `DMMF.Document` and produces the complete TypeScript source string.

```typescript
import type * as DMMF from '@prisma/dmmf'

import { mapScalarToTS } from './typeMap'
import {
  generateModelInterface,
  generateCreateInput,
  generateUpdateInput,
  generateEnum,
  generateClientClass,
  generatePreamble,
} from './template'

export function generateRestClient(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel
  const parts: string[] = []

  // 1. File preamble (header comment, eslint-disable, etc.)
  parts.push(generatePreamble())

  // 2. Generate enum types
  for (const enumDef of enums) {
    parts.push(generateEnum(enumDef))
  }

  // 3. For each model, generate:
  //    - Model interface (scalar + enum fields only)
  //    - CreateInput type (omit auto-generated fields)
  //    - UpdateInput type (all fields optional via Partial)
  for (const model of models) {
    const scalarFields = model.fields.filter(
      (f) => f.kind === 'scalar' || f.kind === 'enum'
    )
    parts.push(generateModelInterface(model.name, scalarFields))
    parts.push(generateCreateInput(model.name, scalarFields))
    parts.push(generateUpdateInput(model.name, scalarFields))
  }

  // 4. Generate the REST client class
  parts.push(generateClientClass(models))

  return parts.join('\n\n')
}
```

Key design decisions:
- Filters out `kind === 'object'` fields (relations) and `kind === 'unsupported'` fields per the requirements.
- Processes `kind === 'enum'` fields and references the generated enum union type by name.
- Generates separate `Create` and `Update` input types per model.

### 2.8 `packages/generator-rest-client/src/typeMap.ts`

Maps Prisma DMMF scalar types to TypeScript types. Based on the type names documented in `DMMF.Field.type` (see `packages/dmmf/src/dmmf.ts` line 86: "BigInt, Boolean, Bytes, DateTime, Decimal, Float, Int, JSON, String, $ModelName").

```typescript
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'string',  // ISO 8601 string for REST APIs (not Date, since JSON serializes dates as strings)
  Json: 'any',
  Bytes: 'string',     // Base64-encoded in REST context
}

/**
 * Maps a DMMF scalar type name to a TypeScript type string.
 * Returns the type name as-is for enum references.
 */
export function mapScalarToTS(dmmfType: string, fieldKind: string): string {
  if (fieldKind === 'enum') {
    return dmmfType  // References the generated enum union type by name
  }
  return SCALAR_TYPE_MAP[dmmfType] ?? 'unknown'
}
```

**Design decision on DateTime**: Use `string` (not `Date`) because REST APIs serialize/deserialize JSON where dates are ISO 8601 strings. This is more accurate for a REST client that works with `fetch()` and `JSON.parse()`.

### 2.9 `packages/generator-rest-client/src/template.ts`

String template helpers for generating TypeScript code. This file contains all the code-generation functions.

```typescript
import type * as DMMF from '@prisma/dmmf'
import type { ReadonlyDeep } from '@prisma/dmmf'

import { mapScalarToTS } from './typeMap'

type Field = DMMF.Field

export function generatePreamble(): string {
  return `// Generated by @prisma/generator-rest-client — do not edit manually.
/* eslint-disable */`
}

export function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values};`
}

export function generateModelInterface(
  modelName: string,
  fields: readonly Field[],
): string {
  const lines = fields.map((f) => {
    const tsType = mapScalarToTS(f.type, f.kind)
    const arrayModifier = f.isList ? '[]' : ''
    const nullModifier = !f.isRequired && !f.isList ? ' | null' : ''
    return `  ${f.name}: ${tsType}${arrayModifier}${nullModifier};`
  })
  return `export interface ${modelName} {\n${lines.join('\n')}\n}`
}

export function generateCreateInput(
  modelName: string,
  fields: readonly Field[],
): string {
  const lines = fields.map((f) => {
    const tsType = mapScalarToTS(f.type, f.kind)
    const arrayModifier = f.isList ? '[]' : ''
    const nullModifier = !f.isRequired && !f.isList ? ' | null' : ''
    // Fields with defaults, auto-increment (@id with default), or isUpdatedAt are optional in create
    const optional = f.hasDefaultValue || f.isUpdatedAt || f.isReadOnly ? '?' : ''
    return `  ${f.name}${optional}: ${tsType}${arrayModifier}${nullModifier};`
  })
  return `export interface ${modelName}CreateInput {\n${lines.join('\n')}\n}`
}

export function generateUpdateInput(
  modelName: string,
  fields: readonly Field[],
): string {
  const lines = fields
    .filter((f) => !f.isId && !f.isReadOnly)  // Cannot update id or read-only fields
    .map((f) => {
      const tsType = mapScalarToTS(f.type, f.kind)
      const arrayModifier = f.isList ? '[]' : ''
      const nullModifier = !f.isRequired && !f.isList ? ' | null' : ''
      return `  ${f.name}?: ${tsType}${arrayModifier}${nullModifier};`
    })
  return `export interface ${modelName}UpdateInput {\n${lines.join('\n')}\n}`
}

export function generateClientClass(
  models: readonly DMMF.Model[],
): string {
  const modelMethods = models.map((model) => {
    const name = model.name
    const lower = name.charAt(0).toLowerCase() + name.slice(1)
    // Determine the id field: explicit @id field, or first field in compound primaryKey
    const idField = model.fields.find((f) => f.isId)
    const idName = idField?.name ?? model.primaryKey?.fields[0] ?? 'id'
    const idType = idField ? mapScalarToTS(idField.type, idField.kind) : 'string'

    return `
  // --- ${name} ---

  async ${lower}FindMany(): Promise<${name}[]> {
    const response = await this.fetch(\`\${this.baseUrl}/${lower}\`);
    return response.json();
  }

  async ${lower}FindUnique(${idName}: ${idType}): Promise<${name} | null> {
    const response = await this.fetch(\`\${this.baseUrl}/${lower}/\${${idName}}\`);
    if (response.status === 404) return null;
    return response.json();
  }

  async ${lower}Create(data: ${name}CreateInput): Promise<${name}> {
    const response = await this.fetch(\`\${this.baseUrl}/${lower}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    return response.json();
  }

  async ${lower}Update(${idName}: ${idType}, data: ${name}UpdateInput): Promise<${name}> {
    const response = await this.fetch(\`\${this.baseUrl}/${lower}/\${${idName}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    return response.json();
  }

  async ${lower}Delete(${idName}: ${idType}): Promise<${name}> {
    const response = await this.fetch(\`\${this.baseUrl}/${lower}/\${${idName}}\`, {
      method: 'DELETE',
    });
    return response.json();
  }`
  })

  return `export class PrismaRestClient {
  private baseUrl: string;
  private fetchFn: typeof fetch;

  constructor(options: { baseUrl: string; fetch?: typeof fetch }) {
    this.baseUrl = options.baseUrl.replace(/\\/+$/, '');
    this.fetchFn = options.fetch ?? globalThis.fetch;
  }

  private async fetch(url: string, init?: RequestInit): Promise<Response> {
    const response = await this.fetchFn(url, init);
    if (!response.ok && response.status !== 404) {
      throw new Error(\`REST API error: \${response.status} \${response.statusText}\`);
    }
    return response;
  }
${modelMethods.join('\n')}
}`
}
```

Key design decisions:
- **Method naming**: Uses `${lowerModelName}FindMany`, `${lowerModelName}Create`, etc. This is a flat namespace avoiding a namespace-per-model pattern, keeping the single-file output simple.
- **ID detection**: Looks for `isId: true` on a field first. Falls back to `model.primaryKey.fields[0]` for compound keys. Final fallback is `'id'`.
- **Configurable fetch**: The constructor accepts an optional `fetch` parameter, defaulting to `globalThis.fetch`. This makes the client testable and allows custom implementations (e.g., for Node.js 16 which lacks global fetch).
- **Error handling**: Throws on non-OK responses except 404 (which returns `null` for `findUnique`).

### 2.10 `packages/generator-rest-client/src/bin.ts`

The standalone CLI entry point for using the generator externally via `generatorHandler` from `@prisma/generator-helper`. This follows the JSON-RPC protocol described at `packages/generator-helper/src/generatorHandler.ts`.

```typescript
import { generatorHandler } from '@prisma/generator-helper'

import { RestClientGenerator } from './generator'

const generator = new RestClientGenerator()

generatorHandler({
  onManifest(config) {
    return generator.getManifest(config)
  },
  async onGenerate(options) {
    await generator.generate(options)
  },
})
```

This makes the generator usable in a Prisma schema as:
```prisma
generator restClient {
  provider = "prisma-generator-rest-client"
  output   = "./generated"
}
```

