import type * as DMMF from '@prisma/dmmf'

import { docComment, fieldType, fileHeader, indent } from './template'

interface ScalarField {
  name: string
  tsType: string
  isRequired: boolean
  isId: boolean
  hasDefaultValue: boolean
  documentation: string | undefined
}

/**
 * Extracts the scalar (non-relation) fields from a DMMF model.
 * Relation fields (kind === 'object') are excluded from the REST interface
 * because the generated client deals with flat JSON payloads.
 */
function extractScalarFields(model: DMMF.Model): ScalarField[] {
  return model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => ({
      name: f.name,
      tsType: fieldType(f.type, f.kind, f.isList, f.isRequired),
      isRequired: f.isRequired,
      isId: f.isId,
      hasDefaultValue: f.hasDefaultValue,
      documentation: f.documentation,
    }))
}

/** Finds the name of the unique identifier field for a model (first `@id` field). */
function idFieldName(model: DMMF.Model): string | undefined {
  const idField = model.fields.find((f) => f.isId)
  if (idField) return idField.name
  // Fall back to compound primary key's first field
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    return model.primaryKey.fields[0]
  }
  return undefined
}

/** Generates the TypeScript interface for a single model. */
function generateModelInterface(model: DMMF.Model, fields: ScalarField[]): string {
  const lines: string[] = []

  lines.push(`${docComment(model.documentation, '')}export interface ${model.name} {`)
  for (const field of fields) {
    const doc = docComment(field.documentation, '  ')
    lines.push(`${doc}  ${field.name}: ${field.tsType}`)
  }
  lines.push('}')

  return lines.join('\n')
}

/**
 * Generates an input type for creating a record.
 * Fields with defaults or that are auto-generated are made optional.
 */
function generateCreateInput(model: DMMF.Model, fields: ScalarField[]): string {
  const lines: string[] = []

  lines.push(`export interface ${model.name}CreateInput {`)
  for (const field of fields) {
    // Fields with defaults, auto-incremented ids, or updatedAt timestamps are optional on create
    const optional = field.hasDefaultValue || field.isId ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${field.tsType}`)
  }
  lines.push('}')

  return lines.join('\n')
}

/** Generates an input type for updating a record (all fields optional). */
function generateUpdateInput(model: DMMF.Model, fields: ScalarField[]): string {
  const lines: string[] = []

  lines.push(`export interface ${model.name}UpdateInput {`)
  for (const field of fields) {
    lines.push(`  ${field.name}?: ${field.tsType}`)
  }
  lines.push('}')

  return lines.join('\n')
}

/** Generates a `WhereUniqueInput` type based on the model's ID field. */
function generateWhereUniqueInput(model: DMMF.Model): string {
  const id = idFieldName(model)
  if (!id) {
    // Models without an ID get a generic record-based unique input
    return `export type ${model.name}WhereUniqueInput = Record<string, unknown>`
  }

  const idField = model.fields.find((f) => f.name === id)
  const tsType = idField ? fieldType(idField.type, idField.kind, idField.isList, true) : 'unknown'
  return `export interface ${model.name}WhereUniqueInput {\n  ${id}: ${tsType}\n}`
}

/** Generates the typed CRUD client class for a single model. */
function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const lowerName = name[0].toLowerCase() + name.slice(1)
  const id = idFieldName(model)

  const idParam = id ? `id` : `id`
  const idInterpolation = id ? '${id}' : '${id}'

  return `export class ${name}Client {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string> = {}) {
    this.#baseUrl = baseUrl
    this.#headers = headers
  }

  /** Retrieve all ${lowerName} records, with optional query parameters. */
  async findMany(params?: Record<string, string>): Promise<${name}[]> {
    const query = params ? '?' + new URLSearchParams(params).toString() : ''
    const response = await fetch(\`\${this.#baseUrl}/${lowerName}\${query}\`, {
      method: 'GET',
      headers: this.#headers,
    })
    if (!response.ok) throw new Error(\`GET /${lowerName} failed: \${response.status}\`)
    return response.json() as Promise<${name}[]>
  }

  /** Retrieve a single ${lowerName} by its unique identifier. */
  async findUnique(${idParam}: ${id ? fieldType(model.fields.find((f) => f.name === id)!.type, model.fields.find((f) => f.name === id)!.kind, false, true) : 'string | number'}): Promise<${name} | null> {
    const response = await fetch(\`\${this.#baseUrl}/${lowerName}/${idInterpolation}\`, {
      method: 'GET',
      headers: this.#headers,
    })
    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`GET /${lowerName}/${idInterpolation} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  /** Create a new ${lowerName} record. */
  async create(data: ${name}CreateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${lowerName}\`, {
      method: 'POST',
      headers: { ...this.#headers, 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`POST /${lowerName} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  /** Update an existing ${lowerName} record by its unique identifier. */
  async update(${idParam}: ${id ? fieldType(model.fields.find((f) => f.name === id)!.type, model.fields.find((f) => f.name === id)!.kind, false, true) : 'string | number'}, data: ${name}UpdateInput): Promise<${name}> {
    const response = await fetch(\`\${this.#baseUrl}/${lowerName}/${idInterpolation}\`, {
      method: 'PATCH',
      headers: { ...this.#headers, 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!response.ok) throw new Error(\`PATCH /${lowerName}/${idInterpolation} failed: \${response.status}\`)
    return response.json() as Promise<${name}>
  }

  /** Delete a ${lowerName} record by its unique identifier. */
  async delete(${idParam}: ${id ? fieldType(model.fields.find((f) => f.name === id)!.type, model.fields.find((f) => f.name === id)!.kind, false, true) : 'string | number'}): Promise<void> {
    const response = await fetch(\`\${this.#baseUrl}/${lowerName}/${idInterpolation}\`, {
      method: 'DELETE',
      headers: this.#headers,
    })
    if (!response.ok) throw new Error(\`DELETE /${lowerName}/${idInterpolation} failed: \${response.status}\`)
  }
}`
}

/** Generates the root REST client that composes all model clients. */
function generateRootClient(models: readonly DMMF.Model[]): string {
  const properties = models
    .map((m) => {
      const lowerName = m.name[0].toLowerCase() + m.name.slice(1)
      return `  readonly ${lowerName} = new ${m.name}Client(this.#baseUrl, this.#headers)`
    })
    .join('\n')

  return `/** Typed REST API client generated from your Prisma schema. */
export class RestClient {
  #baseUrl: string
  #headers: Record<string, string>

  constructor(baseUrl: string, headers: Record<string, string> = {}) {
    this.#baseUrl = baseUrl.replace(/\\/+$/, '')
    this.#headers = headers
  }

${properties}
}`
}

/** Generates enum type declarations. */
function generateEnums(enums: readonly DMMF.DatamodelEnum[]): string {
  return enums
    .map((e) => {
      const values = e.values.map((v) => `  | '${v.name}'`).join('\n')
      const doc = docComment(e.documentation, '')
      return `${doc}export type ${e.name} =\n${values}`
    })
    .join('\n\n')
}

/**
 * Main generation function. Transforms a DMMF document into a complete
 * TypeScript REST client source file.
 */
export function generate(dmmf: DMMF.Document): string {
  const { models, enums } = dmmf.datamodel
  const sections: string[] = [fileHeader()]

  // Enum types
  if (enums.length > 0) {
    sections.push('// ---------- Enums ----------\n')
    sections.push(generateEnums(enums))
    sections.push('')
  }

  // Per-model types and client classes
  for (const model of models) {
    const fields = extractScalarFields(model)

    sections.push(`// ---------- ${model.name} ----------\n`)
    sections.push(generateModelInterface(model, fields))
    sections.push('')
    sections.push(generateCreateInput(model, fields))
    sections.push('')
    sections.push(generateUpdateInput(model, fields))
    sections.push('')
    sections.push(generateWhereUniqueInput(model))
    sections.push('')
    sections.push(generateModelClient(model))
    sections.push('')
  }

  // Root client
  sections.push('// ---------- Root Client ----------\n')
  sections.push(generateRootClient(models))
  sections.push('')

  return sections.join('\n')
}

