import { describe, expect, it } from 'vitest'
import type * as DMMF from '@prisma/dmmf'

import { generate } from '../generator'
import { fieldType, toTsType } from '../template'

function createField(overrides: Partial<DMMF.Field> = {}): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: true,
    isId: true,
    isReadOnly: false,
    hasDefaultValue: true,
    type: 'Int',
    nativeType: null,
    dbName: null,
    default: { name: 'autoincrement', args: [] },
    ...overrides,
  } as DMMF.Field
}

function createModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as DMMF.Model
}

function createDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: { prisma: [] },
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  } as unknown as DMMF.Document
}

describe('toTsType', () => {
  it('maps scalar Prisma types to TypeScript types', () => {
    expect(toTsType('String', 'scalar')).toBe('string')
    expect(toTsType('Int', 'scalar')).toBe('number')
    expect(toTsType('Float', 'scalar')).toBe('number')
    expect(toTsType('Boolean', 'scalar')).toBe('boolean')
    expect(toTsType('DateTime', 'scalar')).toBe('Date')
    expect(toTsType('BigInt', 'scalar')).toBe('bigint')
    expect(toTsType('Json', 'scalar')).toBe('unknown')
    expect(toTsType('Bytes', 'scalar')).toBe('Buffer')
    expect(toTsType('Decimal', 'scalar')).toBe('number')
  })

  it('returns the enum name for enum fields', () => {
    expect(toTsType('Role', 'enum')).toBe('Role')
  })

  it('returns the model name for object (relation) fields', () => {
    expect(toTsType('Post', 'object')).toBe('Post')
  })

  it('returns unknown for unrecognized types', () => {
    expect(toTsType('SomethingNew', 'scalar')).toBe('unknown')
  })
})

describe('fieldType', () => {
  it('wraps list types in array syntax', () => {
    expect(fieldType('String', 'scalar', true, true)).toBe('string[]')
  })

  it('wraps optional types with null union', () => {
    expect(fieldType('String', 'scalar', false, false)).toBe('string | null')
  })

  it('handles optional list types', () => {
    expect(fieldType('String', 'scalar', true, false)).toBe('string[] | null')
  })

  it('leaves required non-list types as-is', () => {
    expect(fieldType('Int', 'scalar', false, true)).toBe('number')
  })
})

describe('generate', () => {
  it('generates a file header', () => {
    const dmmf = createDmmf([])
    const result = generate(dmmf)
    expect(result).toContain('This file was generated by @prisma/generator-rest-client')
    expect(result).toContain('Do not edit it manually')
  })

  it('generates an interface for each model', () => {
    const fields = [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'email', type: 'String', isId: false, isUnique: true, hasDefaultValue: false }),
      createField({ name: 'name', type: 'String', isId: false, isRequired: false, hasDefaultValue: false }),
    ]
    const model = createModel('User', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
    expect(result).toContain('  name: string | null')
  })

  it('generates CreateInput with optional id fields', () => {
    const fields = [
      createField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
      createField({ name: 'title', type: 'String', isId: false, hasDefaultValue: false }),
    ]
    const model = createModel('Post', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface PostCreateInput {')
    expect(result).toContain('  id?: number')
    expect(result).toContain('  title: string')
  })

  it('generates UpdateInput with all fields optional', () => {
    const fields = [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'title', type: 'String', isId: false }),
    ]
    const model = createModel('Post', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface PostUpdateInput {')
    expect(result).toContain('  id?: number')
    expect(result).toContain('  title?: number')
  })

  it('generates WhereUniqueInput with id field', () => {
    const fields = [createField({ name: 'id', type: 'Int', isId: true })]
    const model = createModel('User', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('export interface UserWhereUniqueInput {')
    expect(result).toContain('  id: number')
  })

  it('generates CRUD client class for each model', () => {
    const fields = [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({ name: 'email', type: 'String', isId: false }),
    ]
    const model = createModel('User', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('export class UserClient {')
    expect(result).toContain('async findMany(params?: Record<string, string>): Promise<User[]>')
    expect(result).toContain('async findUnique(id: number): Promise<User | null>')
    expect(result).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(result).toContain('async update(id: number, data: UserUpdateInput): Promise<User>')
    expect(result).toContain('async delete(id: number): Promise<void>')
  })

  it('generates a root RestClient composing all models', () => {
    const userFields = [createField({ name: 'id', type: 'Int', isId: true })]
    const postFields = [createField({ name: 'id', type: 'String', isId: true, type: 'String' })]

    const result = generate(
      createDmmf([createModel('User', userFields), createModel('Post', postFields)]),
    )

    expect(result).toContain('export class RestClient {')
    expect(result).toContain('readonly user = new UserClient(this.#baseUrl, this.#headers)')
    expect(result).toContain('readonly post = new PostClient(this.#baseUrl, this.#headers)')
  })

  it('generates enum types as union types', () => {
    const enums: DMMF.DatamodelEnum[] = [
      {
        name: 'Role',
        values: [
          { name: 'ADMIN', dbName: null },
          { name: 'USER', dbName: null },
        ],
      },
    ]
    const result = generate(createDmmf([], enums))

    expect(result).toContain("export type Role =\n  | 'ADMIN'\n  | 'USER'")
  })

  it('excludes relation (object) fields from interfaces', () => {
    const fields = [
      createField({ name: 'id', type: 'Int', isId: true }),
      createField({
        name: 'posts',
        type: 'Post',
        kind: 'object',
        isList: true,
        isId: false,
        hasDefaultValue: false,
        relationName: 'UserPosts',
        relationFromFields: [],
        relationToFields: [],
      }),
    ]
    const model = createModel('User', fields)
    const result = generate(createDmmf([model]))

    expect(result).not.toContain('posts: Post[]')
    expect(result).toContain('  id: number')
  })

  it('handles String id fields', () => {
    const fields = [
      createField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      createField({ name: 'name', type: 'String', isId: false, hasDefaultValue: false }),
    ]
    const model = createModel('Category', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('async findUnique(id: string): Promise<Category | null>')
    expect(result).toContain('async delete(id: string): Promise<void>')
  })

  it('uses fetch with correct HTTP methods', () => {
    const fields = [createField({ name: 'id', type: 'Int', isId: true })]
    const model = createModel('Item', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain("method: 'GET'")
    expect(result).toContain("method: 'POST'")
    expect(result).toContain("method: 'PATCH'")
    expect(result).toContain("method: 'DELETE'")
  })
})

