  it('handles String id fields', () => {
    const fields = [
      createField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      createField({ name: 'name', type: 'String', isId: false, hasDefaultValue: false }),
    ]
    const model = createModel('Category', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain('async findUnique(id: string): Promise<Category | null>')
    expect(result).toContain('async delete(id: string): Promise<void>')
  })

  it('uses fetch with correct HTTP methods', () => {
    const fields = [createField({ name: 'id', type: 'Int', isId: true })]
    const model = createModel('Item', fields)
    const result = generate(createDmmf([model]))

    expect(result).toContain("method: 'GET'")
    expect(result).toContain("method: 'POST'")
    expect(result).toContain("method: 'PATCH'")
    expect(result).toContain("method: 'DELETE'")
  })
})

