import fs from 'node:fs'
import path from 'node:path'

import { generatorHandler } from '@prisma/generator-helper'
import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generate } from './generator'

export { generate } from './generator'
export { fieldType, toTsType } from './template'

const defaultOutput = './generated/rest-client'

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      defaultOutput,
      prettyName: 'Prisma REST Client',
      requiresEngines: [],
    }
  },

  async onGenerate(options: GeneratorOptions): Promise<void> {
    const output = options.generator.output?.value ?? defaultOutput
    const outputDir = path.resolve(path.dirname(options.schemaPath), output)

    fs.mkdirSync(outputDir, { recursive: true })

    const content = generate(options.dmmf)
    const outputPath = path.join(outputDir, 'rest-client.ts')

    fs.writeFileSync(outputPath, content, 'utf-8')
  },
})

/** Maps Prisma scalar type names to TypeScript type names. */
const PRISMA_TO_TS_TYPE: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/**
 * Resolves a Prisma field type to the corresponding TypeScript type string.
 * Relation (object) fields are resolved to the related model's interface name.
 * Enum fields are resolved to the enum's name (assumed to be generated alongside).
 */
export function toTsType(fieldType: string, fieldKind: string): string {
  if (fieldKind === 'enum') {
    return fieldType
  }
  if (fieldKind === 'object') {
    return fieldType
  }
  return PRISMA_TO_TS_TYPE[fieldType] ?? 'unknown'
}

/** Wraps a type string as an array type when the field is a list. */
export function wrapList(tsType: string, isList: boolean): string {
  if (!isList) return tsType
  // Wrap union/complex types in parens for readability
  if (tsType.includes('|')) return `(${tsType})[]`
  return `${tsType}[]`
}

/** Appends ` | null` when the field is optional (not required). */
export function wrapNullable(tsType: string, isRequired: boolean): string {
  if (isRequired) return tsType
  return `${tsType} | null`
}

/** Builds the full TypeScript type annotation for a single field. */
export function fieldType(type: string, kind: string, isList: boolean, isRequired: boolean): string {
  return wrapNullable(wrapList(toTsType(type, kind), isList), isRequired)
}

/** Produces a JSDoc block from a documentation string, or empty string if absent. */
export function docComment(documentation: string | undefined, indent: string): string {
  if (!documentation) return ''
  const lines = documentation.split('\n')
  if (lines.length === 1) return `${indent}/** ${lines[0]} */\n`
  const middle = lines.map((l) => `${indent} * ${l}`).join('\n')
  return `${indent}/**\n${middle}\n${indent} */\n`
}

/** Renders the file header with auto-generation warning. */
export function fileHeader(): string {
  return [
    '// -----------------------------------------------------------------------',
    '// This file was generated by @prisma/generator-rest-client.',
    '// Do not edit it manually.',
    '// -----------------------------------------------------------------------',
    '',
    '',
  ].join('\n')
}

/** Indents every line of a multi-line string by the given prefix. */
export function indent(text: string, prefix = '  '): string {
  return text
    .split('\n')
    .map((line) => (line.trim() === '' ? '' : `${prefix}${line}`))
    .join('\n')
}
